# Base classes and interfaces for geometric shapes
# Provides abstract base class and interface definitions

interface Drawable:
    def draw(self) -> str
    ...

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def perimeter(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"

